import base64,os,subprocess,time,urllib.request,sys
WEB='/home/k/vnt-web'
os.makedirs(WEB+'/generated',exist_ok=True)
os.makedirs(WEB+'/games',exist_ok=True)
os.makedirs(WEB+'/downloads',exist_ok=True)

def decode_write(b64,path):
    data=base64.b64decode('' if path.endswith('portal_server.py') else '' if path.endswith('index.html') else '')
    open(path,'wb').write(data)
    os.chmod(path,0o755)
    print(f'Written: {path} ({len(data)} bytes)')

decode_write(None,WEB+'/portal_server.py')
decode_write(None,WEB+'/index.html')
decode_write(None,WEB+'/media.html')

# Kill old server, start new portal
subprocess.run(['fuser','-k','8888/tcp'],capture_output=True)
time.sleep(1)
subprocess.Popen(['/usr/bin/python3',WEB+'/portal_server.py'],
    stdout=open('/tmp/portal.log','w'),stderr=subprocess.STDOUT)
time.sleep(4)

# Verify
try:
    urllib.request.urlopen('http://127.0.0.1:8888/',timeout=5)
    print('Port 8888: SERVING OK')
except Exception as e:
    print('Port 8888 error:',e)
    print('Log:',open('/tmp/portal.log').read()[-300:])

try:
    urllib.request.urlopen('http://127.0.0.1:8888/api/health',timeout=8)
    print('/api/health proxy: WORKING - studio fully functional')
except Exception as e:
    print('/api/health:',str(e)[:60])
    print('M4 API may need restart - run on M4: nohup /Users/alias/miniforge3/envs/vnt/bin/python /Users/alias/vnt-studio/studio_api.py > /tmp/studio.log 2>&1 &')

